{
  "name": "bank-balance-temporal",
  "version": "1.0.0",
  "description": "BankBalance workflow with Temporal Update handler and validator",
  "main": "dist/client.js",
  "scripts": {
    "build": "tsc --build",
    "start": "npm run build && node dist/start.js"
  },
  "dependencies": {
    "@temporalio/client": "^1.11.6",
    "@temporalio/worker": "^1.11.6",
    "@temporalio/workflow": "^1.11.6",
    "@temporalio/activity": "^1.11.6",
    "@temporalio/common": "^1.11.6"
  },
  "devDependencies": {
    "typescript": "^5.4.5",
    "@types/node": "^20.0.0"
  }
}

import {
  defineUpdate,
  defineSignal,
  setHandler,
  condition,
} from '@temporalio/workflow';
import { ApplicationFailure } from '@temporalio/common';

// Define the deposit Update: takes a number (amount), returns a number (new balance)
export const depositUpdate = defineUpdate<number, [number]>('deposit');

// Define the finish Signal: no arguments
export const finishSignal = defineSignal('finish');

export async function BankBalanceWorkflow(): Promise<number> {
  let balance = 0;
  let finished = false;

  // Register the finish signal handler
  setHandler(finishSignal, () => {
    finished = true;
  });

  // Register the deposit update handler with a validator
  setHandler(
    depositUpdate,
    (amount: number): number => {
      balance += amount;
      return balance;
    },
    {
      validator: (amount: number): void => {
        if (amount <= 0) {
          throw ApplicationFailure.create({
            message: `Deposit amount must be positive, got: ${amount}`,
            type: 'InvalidAmount',
          });
        }
      },
    }
  );

  // Wait until the finish signal is received (no busy-loop)
  await condition(() => finished);

  return balance;
}

import { Worker, NativeConnection } from '@temporalio/worker';
import * as path from 'path';

async function main(): Promise<void> {
  const apiKey = process.env.TEMPORAL_API_KEY;
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!apiKey || !address || !namespace) {
    throw new Error(
      'Missing required environment variables: TEMPORAL_API_KEY, TEMPORAL_ADDRESS, TEMPORAL_NAMESPACE'
    );
  }

  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'update-handler-ts',
    workflowsPath: path.join(__dirname, 'workflow'),
  });

  console.log('Worker started, polling task queue: update-handler-ts');
  await worker.run();
}

main().catch((err) => {
  console.error('Worker error:', err);
  process.exit(1);
});

import { Client, Connection } from '@temporalio/client';
import { BankBalanceWorkflow, depositUpdate, finishSignal } from './workflow';

async function main(): Promise<void> {
  const apiKey = process.env.TEMPORAL_API_KEY;
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId = process.env.ZEALT_RUN_ID;

  if (!apiKey || !address || !namespace || !runId) {
    throw new Error(
      'Missing required environment variables: TEMPORAL_API_KEY, TEMPORAL_ADDRESS, TEMPORAL_NAMESPACE, ZEALT_RUN_ID'
    );
  }

  const workflowId = `update-wf-${runId}`;

  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({
    connection,
    namespace,
  });

  // Start the BankBalanceWorkflow
  const handle = await client.workflow.start(BankBalanceWorkflow, {
    taskQueue: 'update-handler-ts',
    workflowId,
  });

  console.log(`Workflow started with ID: ${workflowId}`);

  // Send three deposit updates and print the returned new balance for each
  const amounts = [100, 50, 25];
  for (const amount of amounts) {
    const newBalance = await handle.executeUpdate(depositUpdate, {
      args: [amount],
    });
    console.log(`Updated balance: ${newBalance}`);
  }

  // Send the finish signal
  await handle.signal(finishSignal);

  // Await the workflow's final result
  const finalBalance = await handle.result();
  console.log(`Final balance: ${finalBalance}`);

  await connection.close();
}

main().catch((err) => {
  console.error('Client error:', err);
  process.exit(1);
});

import { spawn, ChildProcess } from 'child_process';
import * as path from 'path';

function startWorker(): ChildProcess {
  const workerScript = path.join(__dirname, 'worker.js');
  const worker = spawn(process.execPath, [workerScript], {
    stdio: 'inherit',
    env: process.env,
  });
  worker.on('error', (err) => {
    console.error('Failed to start worker process:', err);
  });
  return worker;
}

async function runClient(): Promise<void> {
  return new Promise<void>((resolve, reject) => {
    const clientScript = path.join(__dirname, 'client.js');
    const client = spawn(process.execPath, [clientScript], {
      stdio: 'inherit',
      env: process.env,
    });
    client.on('error', reject);
    client.on('close', (code) => {
      if (code === 0) {
        resolve();
      } else {
        reject(new Error(`Client process exited with code ${code}`));
      }
    });
  });
}

async function main(): Promise<void> {
  const workerProcess = startWorker();

  // Give the worker a moment to connect and start polling before the client runs
  await new Promise<void>((resolve) => setTimeout(resolve, 3000));

  try {
    await runClient();
  } finally {
    // Shut down the worker once the client has finished
    workerProcess.kill('SIGTERM');
  }
}

main()
  .then(() => {
    process.exit(0);
  })
  .catch((err) => {
    console.error('Error:', err);
    process.exit(1);
  });

